var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우...... 후우우......","JPN":"ふう……ふうう……","ENG":"*Blows on the hand* Brrr...","TWN":"呼……呼……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"또 손에 서리가 내렸네. 그거 입김 분다고 녹기는 해?","JPN":"また手が凍ってる。それ、息を吹きかけただけで治るの？","ENG":"Your hands are all frosty again. Do they get warm when you blow on them?","TWN":"妳手上又結霜了。那樣吹氣就會融化嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이거 받아. 손난로야. 몇 번 흔들고 나면 금방 따듯해져.","JPN":"これ使いな。カイロだよ。何回か振ればすぐ温かくなるから。","ENG":"Take this. It's a handwarmer. Give it a few shakes, and it'll start getting warm.","TWN":"拿著吧，這是暖暖包，搖幾次馬上就會變暖的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 고마워요. 저도 준비해 둘 걸 그랬네요.","JPN":"ああ、ありがとうございます。私も用意しておくべきでしたわ。","ENG":"Ah, thank you. I should have brought some myself.","TWN":"啊，謝謝。我也應該準備一下的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아...... 따듯해......","JPN":"はあ……温かい……","ENG":"Aaah... It's warm...","TWN":"哈啊……好暖……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"신기하네. 자기 능력 때문에 너처럼 고생하는 카운터는 처음 봤어.","JPN":"不思議だね。自分の能力のせいでアンタみたいに苦労するカウンターは初めて見たよ。","ENG":"You're weird. You're the first Counter I've ever met who has trouble with her own ability.","TWN":"真是有趣。第一次見到妳這種會因為自己的能力而吃到苦頭的制裁者。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래도 싸움 실력은 쑥쑥 느는데? 사실 이쪽 방면으로 재능 있는 거 아냐?","JPN":"それでも戦いの腕はどんどん上がってるね。もしかして、こっち方面にも才能があるとか？","ENG":"But your combat skills are improving by the minute. Maybe you're more talented in this area than you think.","TWN":"不過感覺戰鬥實力卻不斷在成長？妳其實很有這方面的才能吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"칭찬은 됐어요. 그런 아부 듣는다고 용병이 될 생각은 없으니까요.","JPN":"褒めても無駄ですわ。そんなお世辞を言われても、傭兵になる気はありませんから。","ENG":"Save your compliments, please. They're not going to make me want to work as a mercenary.","TWN":"別誇我了，就算聽到妳拍馬屁，我也沒有當傭兵的想法。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"좋다고 실실 웃는 주제에 시치미 떼긴.","JPN":"嬉しそうにニコニコ笑ってるくせに、とぼけちゃって。","ENG":"Oh yeah? Try to say that without a smile on your face.","TWN":"妳都在吃吃竊笑了，不要裝傻。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠, 흠! 웃기는 누가 웃어요!","JPN":"オッホン！　笑ってませんわ！","ENG":"W-what? I didn't smile!","TWN":"咳咳！誰笑了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그나저나 에델은 무사한가요? 침식체들이 에델 쪽으로도 달려든 것 같던데요?","JPN":"ところで、エデルは無事ですか？\\n侵食体がエデルの方に押し寄せて行ったみたいですが……","ENG":"Anyway, will Edel be all right? I saw a bunch of C.O.s running in her direction.","TWN":"不過艾瑟兒沒事吧？侵蝕體好像都往艾瑟兒的方向去了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델이라면 괜찮아. 다른 아이들이 늘 지켜 주고 있거든.","JPN":"エデルなら心配いらないよ。他の子たちがいつも守ってくれるから。","ENG":"She'll be fine. Her babies will keep her safe.","TWN":"艾瑟兒不會有事的，其它孩子們一直都在保護她。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아이들?","JPN":"他の子たち？","ENG":"Babies?","TWN":"孩子？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 혹시 그 애완동물 말인가요?","JPN":"ああ、もしかしてペットのことですの？","ENG":"Ah, you mean the pets she's been raising at the mansion?","TWN":"啊，妳是指那些寵物嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"애완동물?","JPN":"ペット？","ENG":"Pets?","TWN":"寵物？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뭐, 비슷하다면 비슷하지?","JPN":"まあ、ペットと言えばペットなのかな。","ENG":"I guess that's close enough of a word.","TWN":"嗯，說像是很像啦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그리고 아니면 뭐 어때!","JPN":"ペットじゃなくても別にいいけどね！","ENG":"And who cares?","TWN":"但不是又如何！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"의뢰주 안전에 신경 꺼도 되는 의뢰라니, 정말 최고잖아!","JPN":"クライアントの安全を気にしなくていい依頼なんて、本当に最高だし！","ENG":"This is the best job ever. I don't even have to care about my client's safety!","TWN":"不用去擔心委託人的安危，這份委託真是太棒了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};